using System.Drawing.Design;
using System.Windows.Forms;
using System.Windows.Forms.Design;

public class MyEditor : UITypeEditor
{
    public override object? EditValue(
        System.ComponentModel.ITypeDescriptorContext? context,
        IServiceProvider provider,
        object? value)
    {
        var editorService = provider.GetService(typeof(IWindowsFormsEditorService))
            as IWindowsFormsEditorService;

        if (editorService is null)
            return value;

        // .NET 9: DropDownControl parameter is now non-nullable.
        // Guard against passing null to avoid ArgumentNullException.
        var control = CreateDropDown(value);
        if (control is not null)
        {
            editorService.DropDownControl(control);
            value = GetValueFromControl(control);
        }

        return value;
    }

    private Control? CreateDropDown(object? currentValue)
    {
        // Returns null when no dropdown is appropriate
        if (currentValue is null)
            return null;

        return new ListBox();
    }

    private object? GetValueFromControl(Control control)
    {
        if (control is ListBox lb && lb.SelectedItem is not null)
            return lb.SelectedItem;
        return null;
    }

    public override UITypeEditorEditStyle GetEditStyle(
        System.ComponentModel.ITypeDescriptorContext? context)
        => UITypeEditorEditStyle.DropDown;
}

